import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { supabase } from '../services/supabaseClient';
import { useTheme } from '../contexts/ThemeContext';

export default function Navbar({ user, setUser }) {
  const navigate = useNavigate();
  const [showDropdown, setShowDropdown] = useState(false);
  const { theme, toggleTheme } = useTheme();

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUser(null);
    setShowDropdown(false);
  };

  const toggleDropdown = () => {
    setShowDropdown(!showDropdown);
  };

  const initials = user?.email ? user.email.charAt(0).toUpperCase() : '?';

  return (
    <div className="w-full bg-white/70 backdrop-blur-xl border-b border-white/30 px-10 py-4 flex items-center justify-between shadow-lg shadow-sapphire/5 dark:bg-deepnavy/70 dark:border-babyblue/10 dark:shadow-black/20 sticky top-0 z-50">
      {/* LOGO */}
      <h1 className="text-xl font-bold cursor-pointer hover:scale-105 transition-transform duration-300" onClick={() => navigate('/')}>
        Research<span className="bg-gradient-to-r from-sapphire to-cornflower bg-clip-text text-transparent">Mate</span>
      </h1>

      {/* MENU */}
      <div className="flex gap-8 text-sapphire/60 font-medium dark:text-babyblue/60">
        <Link to="/" className="relative pb-1 hover:text-sapphire dark:hover:text-babyblue transition-colors duration-300 group">
          <span className="text-sapphire dark:text-babyblue border-b-2 border-sapphire pb-1">Home</span>
          <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-sapphire transition-all duration-300 group-hover:w-full"></span>
        </Link>
        <button className="hover:text-sapphire dark:hover:text-babyblue hover-lift transition-all duration-300">
          AI Assistant
        </button>
        <button className="hover:text-sapphire dark:hover:text-babyblue hover-lift transition-all duration-300">
          Paper Insights
        </button>
        <button className="hover:text-sapphire dark:hover:text-babyblue hover-lift transition-all duration-300">
          Recommendations
        </button>
        <button className="hover:text-sapphire dark:hover:text-babyblue hover-lift transition-all duration-300">
          Simplifier
        </button>
        <button className="hover:text-sapphire dark:hover:text-babyblue hover-lift transition-all duration-300">
          Help
        </button>
      </div>

      {/* RIGHT SIDE */}
      <div className="flex items-center gap-4">
        {/* Theme Icon */}
        <button 
          className="text-sapphire/50 dark:text-babyblue/50 text-lg hover:text-sapphire dark:hover:text-babyblue hover:rotate-12 transition-all duration-300 hover-lift" 
          onClick={toggleTheme}
          title="Toggle theme"
        >
          {theme === 'light' ? '🌙' : '☀️'}
        </button>

        {user ? (
          <div className="relative">
            <button
              onClick={toggleDropdown}
              className="w-10 h-10 bg-gradient-to-br from-sapphire to-cornflower text-white rounded-full flex items-center justify-center text-sm font-semibold hover:scale-110 hover:ring-4 ring-babyblue/30 transition-all duration-300 shadow-lg shadow-sapphire/20"
              title="User menu"
            >
              {initials}
            </button>
            {showDropdown && (
              <div className="absolute right-0 mt-3 w-52 bg-white/90 backdrop-blur-xl border border-babyblue/20 rounded-2xl shadow-2xl shadow-sapphire/10 py-2 z-50 animate-fade-in-up dark:bg-deepnavy-light/90 dark:border-babyblue/10 dark:shadow-black/30">
                <Link
                  to="/profile"
                  className="block px-4 py-3 text-sm text-sapphire dark:text-babyblue hover:bg-periwinkle/30 dark:hover:bg-babyblue/10 hover-lift rounded-xl mx-2 transition-all duration-200"
                  onClick={() => setShowDropdown(false)}
                >
                  Profile
                </Link>
                <button
                  onClick={handleLogout}
                  className="w-full text-left px-4 py-3 text-sm text-red-500 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/30 hover-lift rounded-xl mx-2 transition-all duration-200"
                >
                  Sign Out
                </button>
              </div>
            )}
          </div>
        ) : (
          <button
            onClick={() => navigate("/auth")}
            className="btn shadow-lg shadow-sapphire/20 hover:shadow-xl hover:shadow-sapphire/30"
          >
            Sign In
          </button>
        )}
      </div>
    </div>
  );
}
